### Incremental Indexing
```rust
#[tokio::test]
async fn test_incremental_index_new_remote_source() {
    // Index initial local sessions
    let mut indexer = Indexer::new(&db);
    indexer.add_root(&local_sessions, Provenance::local());
    indexer.index_all().await.unwrap();

    let initial_count = db.conversation_count().await.unwrap();

    // Simulate adding new remote source
    indexer.add_root(&remote_sessions, Provenance::remote("laptop".into()));
    indexer.index_incremental().await.unwrap();

    let final_count = db.conversation_count().await.unwrap();
    assert_eq!(final_count, initial_count + remote_sessions.len());
}
